{
  "grammar": [
    {
      "pattern": "Subject + 要 + 預約 + Time + 的 + Noun",
      "structure": ["Subject", "要", "預約", "Time", "的", "Noun"],
      "explanation_en": "Use this pattern to express the intention to book an appointment for a specific time slot.",
      "title": "Booking an Appointment with 預約",
      "meaning": "To book an appointment for a specific time.",
      "when_to_use": ["When you want to schedule a formal appointment", "When specifying the time and purpose of the booking"],
      "when_not_to_use": ["For casual meetups with friends", "When the time is not specified"],
      "pragmatic_notes": "In Taiwan, 預約 is commonly used for medical appointments, restaurant reservations, and service bookings. It's polite to specify the time clearly.",
      "word_order_notes": "Time phrase must come before the noun being booked.",
      "english_contrast": "English uses 'book an appointment for [time]', while Chinese places the time before the noun.",
      "korean_contrast": "Korean uses '약속을 예약하다' with time markers, similar to Chinese structure.",
      "negative_examples": [
        {
          "text": "我預約要明天門診。",
          "error": "Time phrase should come before the noun, not after the verb."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我預約門診明天。",
          "error": "Time phrase must be placed before the noun '門診'."
        }
      ],
      "transformation_drills": ["Change '明天' to '下個星期' and adjust the sentence.", "Change '門診' to '牙醫' and rephrase."],
      "production_drills": ["Book an appointment for next Monday morning.", "Book a haircut for this Friday afternoon."],
      "common_error_patterns": ["Placing time after the noun", "Omitting 的 between time and noun"],
      "repair_feedback": {
        "word_order": "Put the time before the noun, e.g., '明天' before '門診'.",
        "politeness": "Use 請 or 麻煩 for polite requests.",
        "vocabulary": "Use 預約 for formal bookings, not 約."
      }
    },
    {
      "pattern": "Subject + 想 + 改期 + 到 + New Time",
      "structure": ["Subject", "想", "改期", "到", "New Time"],
      "explanation_en": "Use this pattern to express the desire to reschedule an appointment to a new time.",
      "title": "Rescheduling with 改期",
      "meaning": "To change the date of an appointment.",
      "when_to_use": ["When you need to move an existing appointment to a different time", "When informing the service provider of the change"],
      "when_not_to_use": ["For canceling an appointment entirely", "For casual plans with friends"],
      "pragmatic_notes": "In Taiwan, 改期 is polite and direct. It's common to apologize briefly before stating the change, e.g., '不好意思，我想改期。'",
      "word_order_notes": "The new time follows 到, indicating the target time.",
      "english_contrast": "English uses 'reschedule to [time]', while Chinese uses '改期到[time]'.",
      "korean_contrast": "Korean uses '날짜를 변경하다' with '로' for the new time, similar to '到'.",
      "negative_examples": [
        {
          "text": "我想改期明天。",
          "error": "Missing 到 before the new time."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我想改期到。",
          "error": "New time must be specified after 到."
        }
      ],
      "transformation_drills": ["Change '明天' to '下個星期二' and adjust.", "Change '改期' to '取消' and rephrase."],
      "production_drills": ["Reschedule your appointment to next Thursday.", "Reschedule your dental checkup to the afternoon."],
      "common_error_patterns": ["Omitting 到 before the new time", "Using 改期 for cancellations"],
      "repair_feedback": {
        "word_order": "Always include 到 before the new time.",
        "politeness": "Start with 不好意思 to soften the request.",
        "vocabulary": "Use 改期 for date changes, 取消 for cancellations."
      }
    },
    {
      "pattern": "Subject + 想 + 確認 + 預約 + 的 + Details",
      "structure": ["Subject", "想", "確認", "預約", "的", "Details"],
      "explanation_en": "Use this pattern to confirm the details of an appointment, such as time, date, or location.",
      "title": "Confirming an Appointment with 確認",
      "meaning": "To verify the details of a booking.",
      "when_to_use": ["When you want to double-check appointment details", "When ensuring there are no misunderstandings"],
      "when_not_to_use": ["For making a new appointment", "For casual inquiries"],
      "pragmatic_notes": "In Taiwan, 確認 is often used in service contexts. It's polite to confirm before the appointment day, e.g., '我想確認明天的預約。'",
      "word_order_notes": "The details (e.g., time, date) come after 的, modifying 預約.",
      "english_contrast": "English uses 'confirm the appointment for [details]', while Chinese places details after 的.",
      "korean_contrast": "Korean uses '예약을 확인하다' with details following, similar structure.",
      "negative_examples": [
        {
          "text": "我想確認預約時間。",
          "error": "Missing 的 between 預約 and 時間."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我想確認的預約時間。",
          "error": "的 should be between 預約 and the detail, not after 確認."
        }
      ],
      "transformation_drills": ["Change '時間' to '日期' and adjust.", "Change '確認' to '取消' and rephrase."],
      "production_drills": ["Confirm your appointment time for tomorrow.", "Confirm the location of your appointment."],
      "common_error_patterns": ["Misplacing 的 in the phrase", "Using 確認 for new bookings"],
      "repair_feedback": {
        "word_order": "Place 的 between 預約 and the detail, e.g., '預約的時間'.",
        "politeness": "Use 請問 for polite confirmation.",
        "vocabulary": "Use 確認 for verification, not for booking."
      }
    }
  ]
}
